// v9: Determine input mode based on incoming data
const input = $input.first().json;

let mode = 'unknown';
let overrides = input.overrides || {};
let raw_input = input;

if (input.study_id) {
  mode = 'study';
} else if (input.legacy_mode) {
  mode = 'legacy';
} else if (input.simulation && input.influent) {
  mode = 'direct';
} else if (input.template || input.flow_m3_d || input.COD_mg_L) {
  // Auto-detect legacy format (flat parameters without explicit flag)
  mode = 'legacy';
} else {
  // No simulation input provided - use default legacy parameters for manual testing
  // This allows the workflow to run with Manual Trigger without webhook input
  mode = 'legacy';
  raw_input = {
    template: 'mle_mbr_asm2d',
    timeout_seconds: 300,
    check_interval_seconds: 60,
    hard_cancel_buffer: 120,
    flow_m3_d: 4000,
    temperature_C: 20,
    COD_mg_L: 350,
    NH4_mg_L: 25,
    TP_mg_L: 8,
    TSS_mg_L: 220
  };
}

return {
  json: {
    mode: mode,
    raw_input: raw_input,
    overrides: overrides
  }
};

// v9: Fetch study configuration from Supabase
const env = $('Env Parameters').first().json;
const inputData = $input.first().json;

const studyId = inputData.raw_input.study_id;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: `${env.supabase_url}/rest/v1/studies?study_id=eq.${encodeURIComponent(studyId)}&select=*`,
  headers: {
    'apikey': env.supabase_key,
    'Authorization': `Bearer ${env.supabase_key}`
  }
});

if (!response || response.length === 0) {
  throw new Error(`Study not found: ${studyId}`);
}

const study = response[0];

return {
  json: {
    mode: 'study',
    study_id: study.study_id,
    study_name: study.name,
    study_description: study.description,
    category: study.category,
    config: study.config,
    overrides: inputData.overrides
  }
};

// v9: Transform v8 legacy format to v9 schema
const inputData = $input.first().json;
const legacy = inputData.raw_input;

const config = {
  simulation: {
    template: legacy.template || 'mle_mbr_asm2d',
    model_type: legacy.model_type || 'ASM2d',
    timeout_seconds: legacy.timeout_seconds || 300,
    check_interval_seconds: legacy.check_interval_seconds || 60,
    hard_cancel_buffer: legacy.hard_cancel_buffer || 120,
    duration_days: legacy.duration_days || 1.0
  },
  influent: {
    flow_m3_d: legacy.flow_m3_d || 4000,
    simplified: {
      COD_mg_L: legacy.COD_mg_L || 350,
      NH4_mg_L: legacy.NH4_mg_L || 25,
      TP_mg_L: legacy.TP_mg_L || 8,
      TSS_mg_L: legacy.TSS_mg_L || 220,
      temperature_C: legacy.temperature_C || 20
    }
  }
};

// Include convergence settings if provided
if (legacy.run_to_convergence) {
  config.convergence = {
    run_to_convergence: true,
    convergence_atol: legacy.convergence_atol || 0.1,
    max_duration_days: legacy.max_duration_days || 60
  };
}

// Include SRT control if provided
if (legacy.target_srt_days) {
  config.srt_control = {
    target_srt_days: legacy.target_srt_days,
    srt_tolerance: legacy.srt_tolerance || 0.1
  };
}

return {
  json: {
    mode: 'legacy',
    config: config,
    overrides: inputData.overrides
  }
};

// v9: Pass through direct mode config
const inputData = $input.first().json;

// Direct mode - use the input as config directly
const config = { ...inputData.raw_input };
delete config.overrides; // Remove overrides from config

return {
  json: {
    mode: 'direct',
    config: config,
    overrides: inputData.overrides
  }
};

// v9: Deep merge overrides into configuration
const inputData = $input.first().json;

function deepMerge(target, source) {
  const output = { ...target };
  for (const key in source) {
    if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
      output[key] = deepMerge(target[key] || {}, source[key]);
    } else if (source[key] !== undefined) {
      output[key] = source[key];
    }
  }
  return output;
}

const config = inputData.config;
const finalConfig = deepMerge(config, inputData.overrides || {});

return {
  json: {
    mode: inputData.mode,
    study_id: inputData.study_id || null,
    study_name: inputData.study_name || null,
    study_description: inputData.study_description || null,
    category: inputData.category || null,
    config: finalConfig,
    overrides_applied: Object.keys(inputData.overrides || {}).length > 0
  }
};

// v9: Generate or validate session_id
const env = $('Env Parameters').first().json;
const configData = $input.first().json;

let session_id = env.session_id;
let analysis_type = env.analysis_type || 'WasteWater';

// Auto-generate session_id if not provided
if (!session_id || session_id.trim() === '') {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  const hours = String(now.getHours()).padStart(2, '0');
  const minutes = String(now.getMinutes()).padStart(2, '0');

  // Include study_id in session name if available, otherwise use Test_Session prefix
  const prefix = configData.study_id ? configData.study_id : 'Test_Session';
  session_id = `${prefix}-${year}-${month}-${day}_${hours}-${minutes}`;
}

// Sanitize session_id for safe path usage
session_id = session_id
  .replace(/:/g, '-')           // Replace colons with hyphens (Windows compatibility)
  .replace(/\s+/g, '_')         // Replace spaces with underscores
  .replace(/[<>"|?*]/g, '')     // Remove invalid path characters
  .substring(0, 60);            // Enforce 60 character max length

return {
  json: {
    ...configData,
    session_id: session_id,
    analysis_type: analysis_type,
    session_generated: !env.session_id || env.session_id.trim() === ''
  }
};

// v9: Build simulation payload from merged configuration
const env = $('Env Parameters').first().json;
const configData = $('Generate Session ID').first().json;
const healthData = $input.first().json;

const version = healthData.version || 'unknown';
const environment = healthData.environment || 'unknown';

const config = configData.config;
const sim = config.simulation || {};
const influent = config.influent || {};

// Determine temperature
let temperature_K;
if (influent.temperature_K) {
  temperature_K = influent.temperature_K;
} else if (influent.simplified && influent.simplified.temperature_C) {
  temperature_K = influent.simplified.temperature_C + 273.15;
} else {
  temperature_K = 293.15; // 20°C default
}

// Build concentrations
let concentrations;
if (influent.concentrations) {
  // Direct concentrations provided (e.g., mADM1)
  concentrations = influent.concentrations;
} else if (influent.simplified) {
  // Calculate from simplified input (ASM2d style)
  const s = influent.simplified;
  const cod_dist = s.cod_distribution || { f_soluble: 0.5, f_fermentable: 0.5, f_acetate: 0.15 };
  const tss_dist = s.tss_distribution || { f_inert: 0.25, f_biodegradable_factor: 0.5 };

  const S_F = (s.COD_mg_L || 350) * cod_dist.f_soluble * cod_dist.f_fermentable;
  const S_A = (s.COD_mg_L || 350) * cod_dist.f_soluble * cod_dist.f_acetate;
  const X_S = (s.COD_mg_L || 350) * (1 - cod_dist.f_soluble);
  const X_I = (s.TSS_mg_L || 220) * tss_dist.f_inert;
  const X_S_total = X_S + ((s.TSS_mg_L || 220) * (1 - tss_dist.f_inert) * tss_dist.f_biodegradable_factor);

  concentrations = {
    S_O2: 0,
    S_F: Math.round(S_F * 10) / 10,
    S_A: Math.round(S_A * 10) / 10,
    S_I: 10,
    S_NH4: s.NH4_mg_L || 25,
    S_N2: 0,
    S_NO3: 0,
    S_PO4: s.TP_mg_L || 8,
    S_ALK: 300,
    X_I: Math.round(X_I * 10) / 10,
    X_S: Math.round(X_S_total * 10) / 10,
    X_H: 30,
    X_PAO: 0,
    X_PP: 0,
    X_PHA: 0,
    X_AUT: 0,
    X_MeOH: 0,
    X_MeP: 0,
    H2O: 1000
  };
}

// Determine display name
let displayName = configData.study_name || sim.template || 'Simulation';

return {
  json: {
    // v9 metadata
    startup_message: `Processing: ${displayName}`,
    server_version: version,
    environment: environment,
    mode: configData.mode,
    study_id: configData.study_id,
    study_name: configData.study_name,
    study_description: configData.study_description,
    category: configData.category,
    overrides_applied: configData.overrides_applied,

    // Session info
    session_id: configData.session_id,
    analysis_type: configData.analysis_type,

    // Simulation parameters
    template: sim.template || 'mle_mbr_asm2d',
    model_type: sim.model_type || 'ASM2d',
    flow_m3_d: influent.flow_m3_d || 4000,
    temperature_K: temperature_K,
    concentrations: concentrations,

    // Timing parameters
    duration_days: sim.duration_days || 1.0,
    timeout_seconds: sim.timeout_seconds || 300,
    check_interval_seconds: sim.check_interval_seconds || 60,
    hard_cancel_buffer: sim.hard_cancel_buffer || 120,

    // Optional advanced configs
    kinetic_params: config.kinetic_params || {},
    reactor_config: config.reactor_config || {},
    convergence: config.convergence || {},
    srt_control: config.srt_control || {},

    // For reporting - include original simplified values
    input_simplified: influent.simplified || null,
    input_config: config,

    // Timing
    start_time: Date.now(),
    iteration: 0
  }
};

