// Display submission error
const errorData = $input.first().json;

return {
  json: {
    error: 'Simulation submission failed',
    error_details: errorData.error || errorData.message || JSON.stringify(errorData),
    suggestion: 'Check server logs or try again later'
  }
};

// Merge job_id with existing data
const prevData = $('Prepare Simulation').first().json;
const submitResponse = $input.first().json;

return {
  json: {
    ...prevData,
    job_id: submitResponse.job_id,
    job_status: submitResponse.status,
    submit_message: submitResponse.message
  }
};

// v9: Evaluate status and timeout conditions using config values
const prevData = $('Store Job ID').first().json;
const statusResponse = $input.first().json;

const timeout_seconds = prevData.timeout_seconds || 300;
const hard_cancel_buffer = prevData.hard_cancel_buffer || 120;

const elapsed_seconds = Math.round((Date.now() - prevData.start_time) / 1000);
const iteration = (prevData.iteration || 0) + 1;
const hard_cancel_threshold = timeout_seconds + hard_cancel_buffer;

// Determine exit condition
let exit_condition = null;
let should_continue = true;
let should_terminate = false;

if (statusResponse.status === 'completed' || statusResponse.status === 'failed') {
  exit_condition = statusResponse.status;
  should_continue = false;
} else if (elapsed_seconds >= hard_cancel_threshold) {
  exit_condition = 'hard_cancel';
  should_continue = false;
  should_terminate = true;
} else if (elapsed_seconds >= timeout_seconds) {
  exit_condition = 'timeout';
  should_continue = false;
}

return {
  json: {
    ...prevData,
    current_status: statusResponse.status,
    elapsed_seconds: elapsed_seconds,
    elapsed_from_api: statusResponse.elapsed_time_seconds,
    iteration: iteration,
    progress_message: `Simulation running... elapsed time: ${elapsed_seconds}s (timeout: ${timeout_seconds}s)`,
    exit_condition: exit_condition,
    should_continue: should_continue,
    should_terminate: should_terminate
  }
};

// v9: Combine all data for report generation with study metadata
const evalData = $('Evaluate Status').first().json;
const resultsResponse = $input.first().json;

// Extract results safely
const results = resultsResponse.results || {};
const performance = results.performance || {};
const effluent = results.effluent || {};
const reactor = results.reactor || {};

const cod = performance.cod || {};
const nitrogen = performance.nitrogen || {};
const phosphorus = performance.phosphorus || {};
const tss = performance.tss || {};

// Determine overall assessment
let assessment = 'Incomplete';
if (evalData.exit_condition === 'completed') {
  const cod_removal = cod.removal_pct || 0;
  const nh4_eff = effluent.NH4_mg_N_L || 999;

  if (cod_removal > 95 && nh4_eff < 1) {
    assessment = 'Excellent';
  } else if (cod_removal > 85 && nh4_eff < 5) {
    assessment = 'Good';
  } else if (cod_removal > 75) {
    assessment = 'Needs Optimization';
  } else {
    assessment = 'Poor';
  }
}

let status_text = evalData.exit_condition;
if (status_text === 'hard_cancel') status_text = 'Terminated (hard cancel)';
if (status_text === 'timeout') status_text = 'Timed Out';
if (status_text === 'completed') status_text = 'Completed';
if (status_text === 'failed') status_text = 'Failed';

// Get simplified influent values or reconstruct from config
const simplified = evalData.input_simplified || {};

return {
  json: {
    report_date: new Date().toISOString(),
    job_id: evalData.job_id,
    session_id: evalData.session_id,
    analysis_type: evalData.analysis_type,
    template: evalData.template,
    model_type: evalData.model_type,
    status: status_text,
    elapsed_seconds: evalData.elapsed_seconds,
    timeout_setting: evalData.timeout_seconds,
    server_version: evalData.server_version,
    assessment: assessment,

    // v9 study metadata
    mode: evalData.mode,
    study_id: evalData.study_id,
    study_name: evalData.study_name,
    study_description: evalData.study_description,
    category: evalData.category,
    overrides_applied: evalData.overrides_applied,

    influent: {
      flow_m3_d: evalData.flow_m3_d,
      COD_mg_L: simplified.COD_mg_L || 'N/A',
      TSS_mg_L: simplified.TSS_mg_L || 'N/A',
      NH4_mg_L: simplified.NH4_mg_L || 'N/A',
      TP_mg_L: simplified.TP_mg_L || 'N/A',
      temperature_C: simplified.temperature_C || ((evalData.temperature_K || 293.15) - 273.15)
    },
    reactor: {
      type: reactor.type || 'N/A',
      V_total_m3: reactor.V_total_m3 || 'N/A',
      HRT_hours: reactor.HRT_hours || 'N/A',
      SRT_days: typeof reactor.SRT_days === 'number' ? reactor.SRT_days.toFixed(1) : 'N/A',
      DO_aerobic: reactor.DO_aerobic_mg_L || 'N/A'
    },
    effluent: {
      COD_mg_L: effluent.COD_mg_L ? effluent.COD_mg_L.toFixed(2) : 'N/A',
      TSS_mg_L: effluent.TSS_mg_L ? effluent.TSS_mg_L.toFixed(2) : 'N/A',
      NH4_mg_L: effluent.NH4_mg_N_L ? effluent.NH4_mg_N_L.toFixed(2) : 'N/A',
      NO3_mg_L: effluent.NO3_mg_N_L ? effluent.NO3_mg_N_L.toFixed(2) : 'N/A',
      PO4_mg_L: effluent.PO4_mg_P_L ? effluent.PO4_mg_P_L.toFixed(2) : 'N/A'
    },
    removal: {
      COD_pct: cod.removal_pct ? cod.removal_pct.toFixed(1) : 'N/A',
      TSS_pct: tss.removal_pct ? tss.removal_pct.toFixed(1) : 'N/A',
      NH4_pct: nitrogen.removal?.NH4_removal_pct ? nitrogen.removal.NH4_removal_pct.toFixed(1) : 'N/A',
      TN_pct: nitrogen.removal?.TN_removal_pct ? nitrogen.removal.TN_removal_pct.toFixed(1) : 'N/A',
      TP_pct: phosphorus.removal?.TP_removal_pct ? phosphorus.removal.TP_removal_pct.toFixed(1) : 'N/A'
    },
    nitrification_pct: nitrogen.removal?.nitrification_efficiency_pct ? nitrogen.removal.nitrification_efficiency_pct.toFixed(1) : 'N/A',
    denitrification_pct: nitrogen.removal?.denitrification_efficiency_pct ? nitrogen.removal.denitrification_efficiency_pct.toFixed(1) : 'N/A',
    raw_results: resultsResponse
  }
};

// v9: Prepare data for server-side AI analysis with study context
const env = $('Env Parameters').first().json;
const data = $input.first().json;

// Remove raw_results to keep payload manageable
const { raw_results, ...cleanData } = data;

// Build input parameters object for the analysis
const inputParameters = {
  template: data.template,
  model_type: data.model_type,
  influent: data.influent,
  reactor: data.reactor,
  timeout_setting: data.timeout_setting,
  // v9 additions
  mode: data.mode,
  study_id: data.study_id,
  study_name: data.study_name,
  study_description: data.study_description,
  category: data.category
};

// Build analysis request with optional override_prompt
const analysisRequest = {
  results: cleanData,
  input_parameters: inputParameters,
  model: env.ai_model || 'gpt-4o',
  temperature: 0.7,
  max_tokens: 4000
};

// Add override_prompt if provided
if (env.override_prompt && env.override_prompt.trim()) {
  analysisRequest.override_prompt = env.override_prompt.trim();
}

return {
  json: {
    ...data,
    analysis_request: analysisRequest
  }
};

// Extract AI analysis from server response and merge with original data
const prevData = $('Prepare AI Analysis Request').first().json;
const serverResponse = $input.first().json;

// Extract the markdown analysis from server response
let ai_analysis = '';
let ai_analysis_error = null;
let ai_model = 'unknown';

if (serverResponse.status === 'success' && serverResponse.analysis) {
  ai_analysis = serverResponse.analysis;
  ai_model = serverResponse.model_used || 'gpt-4o';
} else if (serverResponse.detail) {
  // Server returned an error
  ai_analysis_error = serverResponse.detail;
  ai_analysis = `## AI Analysis Unavailable\n\nThe AI analysis could not be completed:\n\n\`${ai_analysis_error}\`\n\nPlease review the simulation results manually.`;
  ai_model = 'error';
} else {
  ai_analysis_error = 'Unexpected response format from server';
  ai_analysis = `## AI Analysis Unavailable\n\nUnexpected response format received. Please review the simulation results manually.`;
  ai_model = 'error';
}

// Remove the analysis request data, keep the clean results
const { analysis_request, ...cleanPrevData } = prevData;

return {
  json: {
    ...cleanPrevData,
    ai_analysis: ai_analysis,
    ai_analysis_error: ai_analysis_error,
    ai_model: ai_model,
    ai_usage: serverResponse.usage || null
  }
};

// Handle AI Analysis API error - provide fallback
const prevData = $('Prepare AI Analysis Request').first().json;
const errorResponse = $input.first().json;

// Remove the analysis request data
const { analysis_request, ...cleanPrevData } = prevData;

const errorMessage = errorResponse.detail || errorResponse.message || errorResponse.error?.message || JSON.stringify(errorResponse);

return {
  json: {
    ...cleanPrevData,
    ai_analysis: `## AI Analysis Unavailable\n\nThe AI analysis could not be completed due to an error:\n\n\`${errorMessage}\`\n\nThis may be because:\n- The OPENAI_API_KEY is not configured on the server\n- The server's AI analysis endpoint is unavailable\n- Network connectivity issues\n\nPlease review the simulation results manually.`,
    ai_analysis_error: errorMessage,
    ai_model: 'error',
    ai_usage: null
  }
};

// v9: Generate HTML report with study metadata and AI analysis
const data = $input.first().json;

// Extract only what we need (exclude raw_results to reduce payload size)
const { raw_results, ...reportData } = data;

const incomplete_note = data.status !== 'Completed' 
  ? '<div class="warning">Note: This simulation did not complete within the allocated time. Results shown are partial and may not represent steady-state conditions.</div>'
  : '';

// v9: Study mode banner
let study_banner = '';
if (data.mode === 'study' && data.study_name) {
  study_banner = `
  <div class="study-banner">
    <h3>Study: ${data.study_name}</h3>
    <p>${data.study_description || ''}</p>
    <p><strong>Category:</strong> ${data.category || 'N/A'} | <strong>Study ID:</strong> ${data.study_id}</p>
    ${data.overrides_applied ? '<p class="overrides-note">Note: Custom overrides were applied to this study configuration.</p>' : ''}
  </div>`;
}

// Convert markdown AI analysis to basic HTML
let ai_analysis_html = data.ai_analysis || 'AI analysis not available.';
// Basic markdown to HTML conversion
ai_analysis_html = ai_analysis_html
  .replace(/^### (.*$)/gm, '<h3>$1</h3>')
  .replace(/^## (.*$)/gm, '<h2>$1</h2>')
  .replace(/^# (.*$)/gm, '<h1>$1</h1>')
  .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
  .replace(/\*([^*]+)\*/g, '<em>$1</em>')
  .replace(/`([^`]+)`/g, '<code>$1</code>')
  .replace(/^- (.*$)/gm, '<li>$1</li>')
  .replace(/^\d+\. (.*$)/gm, '<li>$1</li>')
  .replace(/\n\n/g, '</p><p>')
  .replace(/\n/g, '<br>');

// Wrap list items
ai_analysis_html = ai_analysis_html.replace(/(<li>.*<\/li>)+/g, '<ul>$&</ul>');

// Generate full HTML report
const htmlReport = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>Wastewater Simulation Report - ${data.session_id}</title>
  <style>
    body { font-family: Arial, sans-serif; margin: 40px; line-height: 1.6; color: #333; }
    h1 { color: #2c3e50; border-bottom: 3px solid #3498db; padding-bottom: 10px; }
    h2 { color: #34495e; margin-top: 30px; border-bottom: 1px solid #bdc3c7; padding-bottom: 5px; }
    h3 { color: #5d6d7e; margin-top: 20px; }
    table { border-collapse: collapse; width: 100%; margin: 20px 0; }
    th, td { border: 1px solid #ddd; padding: 12px; text-align: left; }
    th { background-color: #3498db; color: white; }
    tr:nth-child(even) { background-color: #f2f2f2; }
    hr { border: none; border-top: 1px solid #bdc3c7; margin: 30px 0; }
    .warning { background: #fff3cd; border-left: 4px solid #ffc107; padding: 15px 20px; margin: 20px 0; }
    .header-info { background: #f8f9fa; padding: 15px; border-radius: 5px; margin-bottom: 20px; }
    .header-info p { margin: 5px 0; }
    .assessment { font-size: 1.2em; font-weight: bold; color: #27ae60; }
    .section { margin-bottom: 30px; }
